# src/api/retry.py
import asyncio, logging, time
from anthropic import AsyncAnthropic, APIStatusError, APITimeoutError, RateLimitError
from src.routing.classifier import Tier, TIER_CONFIG

logger = logging.getLogger(__name__)
client = AsyncAnthropic()

async def _single_call(model, max_tokens, system, messages, timeout_s):
    try:
        return await asyncio.wait_for(
            client.messages.create(
                model=model, max_tokens=max_tokens,
                system=system, messages=messages
            ),
            timeout=timeout_s,
        )
    except asyncio.TimeoutError:
        raise APITimeoutError(request=None)

async def call_with_fallback(
    tier: Tier,
    system: str,
    messages: list,
    *,
    audit_log_fn=None,
) -> dict:
    """
    Execute an API call with the retry and fallback sequence defined in
    the Fallback and Retry Policy ADR for the given tier.
    Returns {"response": ..., "model_used": ..., "fallback_invoked": bool}
    or raises RuntimeError with structured error_code.
    """
    cfg = TIER_CONFIG[tier]
    model, max_tokens, timeout_s = cfg["model"], cfg["max_tokens"], cfg["timeout_s"]

    backoffs = {Tier.SIMPLE: [1, 2, 4], Tier.STANDARD: [2, 4, 8], Tier.COMPLEX: [5, 10, 20]}

    # Primary retry loop
    for attempt, wait_s in enumerate([0] + backoffs[tier]):
        if wait_s:
            await asyncio.sleep(wait_s)
        try:
            resp = await _single_call(model, max_tokens, system, messages, timeout_s)
            if resp.stop_reason == "content_filter":
                if audit_log_fn:
                    audit_log_fn(system, messages, tier)
                raise RuntimeError("CONTENT_FILTERED")
            return {"response": resp, "model_used": model, "fallback_invoked": False}
        except RateLimitError as e:
            retry_after = int(e.response.headers.get("retry-after", 30))
            if attempt == len(backoffs[tier]):  # last attempt
                if tier in (Tier.SIMPLE, Tier.COMPLEX):
                    break  # go to fallback
                raise RuntimeError("RATE_LIMITED")
            await asyncio.sleep(retry_after)
        except (APIStatusError, APITimeoutError):
            if attempt == len(backoffs[tier]):
                break  # go to fallback

    # Fallback
    fallback_model = None
    if tier == Tier.SIMPLE:
        fallback_model = TIER_CONFIG[Tier.STANDARD]["model"]
        fallback_timeout = TIER_CONFIG[Tier.STANDARD]["timeout_s"]
    elif tier == Tier.COMPLEX:
        fallback_model = TIER_CONFIG[Tier.STANDARD]["model"]
        fallback_timeout = TIER_CONFIG[Tier.STANDARD]["timeout_s"]
    else:
        raise RuntimeError("MODEL_UNAVAILABLE")

    logger.warning("Fallback invoked: %s → %s", model, fallback_model)
    try:
        resp = await _single_call(fallback_model, max_tokens, system, messages, fallback_timeout)
        return {"response": resp, "model_used": fallback_model, "fallback_invoked": True}
    except Exception:
        if tier == Tier.COMPLEX:
            raise RuntimeError("DEFER_TO_QUEUE")
        raise RuntimeError("MODEL_UNAVAILABLE")
